        active_bg = self.colors["purple2"] if primary else "#f8fafc"
        btn = tk.Button(
            parent,
            text=text,
            command=command,
            bg=bg,
            fg=fg,
            activebackground=active_bg,
            activeforeground=fg,
            relief="flat",
            bd=0,
            padx=12,
            pady=8,
            font=("Segoe UI", 9, "bold"),
            cursor="hand2",
            width=width or 0,
            highlightthickness=1,
            highlightbackground=self.colors["purple"] if not primary else self.colors["purple"],
        )
        return btn

