    def _update_metrics_and_tables(self, report: dict):
        summary = report.get("summary", {})
        results = report.get("results", [])

        self.metric_devices.configure(text=str(summary.get("active_hosts_found", 0)))
        self.metric_ports.configure(text=str(summary.get("open_ports_total", 0)))
        self.metric_high.configure(text=str(summary.get("high_risk_findings", 0)))
        self.metric_report.configure(text="Bereit")

        for item in self.tree.get_children():
            self.tree.delete(item)

        def risk_for_host(host):
            ports = host.get("open_ports", [])
            if any(p.get("risk") == "hoch" for p in ports):
                return "hoch"
            if any(p.get("risk") == "mittel" for p in ports):
                return "mittel"
            if any(p.get("risk") == "niedrig" for p in ports):
                return "niedrig"
            return "-"

        if results:
            self.empty_label.grid_remove()
            self.tree.grid()
        else:
            self.tree.grid_remove()
            self.empty_label.configure(text="Keine aktiv sichtbaren Geräte gefunden.")
            self.empty_label.grid()

        for host in results[:30]:
            ports = host.get("open_ports", [])
            port_text = ", ".join(f"{p.get('port')} {p.get('service')}" for p in ports[:3]) if ports else "Keine offenen Standardports"
            if len(port_text) > 46:
                port_text = port_text[:43] + "..."
            self.tree.insert("", "end", values=(
                host.get("ip", "-"),
                host.get("hostname") or host.get("mac_address") or "-",
                port_text,
                risk_for_host(host),
                "Erreichbar" if host.get("detection_sources") else "-"
            ))

        for child in self.risk_list.winfo_children():
            child.destroy()

        findings = []
        for host in results:
            for p in host.get("open_ports", []):
                findings.append((p.get("service", "Dienst"), p.get("recommendation", ""), p.get("risk", "niedrig"), host.get("ip", "")))

        risk_order = {"hoch": 0, "mittel": 1, "niedrig": 2}
        findings.sort(key=lambda x: risk_order.get(x[2], 3))

        if not findings:
            self._risk_item("Keine auffälligen offenen Dienste", "Auf den geprüften Standardports wurden keine kritischen Dienste erkannt.", "niedrig")
        else:
            for service, rec, risk, ip in findings[:6]:
                self._risk_item(f"{service} auf {ip}", rec, risk)

    def focus_devices(self):
        self.devices_title.configure(fg=self.colors["purple"])
        self.root.after(900, lambda: self.devices_title.configure(fg=self.colors["text"]))

